SELECT AVG(target_percent_id) AS average_target_percent
FROM target_percent_ids
WHERE species_id = 1;

SELECT gene_id, orthologue_confidence
FROM orthologues
WHERE orthologue_confidence > 0.9;

SELECT gene_id, dn_ds_ratio
FROM dn_ds_ratios
WHERE dn_ds_ratio > 0.05;

SELECT AVG(query_percent_id) AS average_query_percent_id
   FROM query_percent_ids
   WHERE gene_id = 1;

SELECT species_id, gene_id, AVG(dn_ds_ratio) AS average_dn_ds_ratio
FROM dn_ds_ratios
GROUP BY species_id, gene_id;

SELECT method_description 
FROM sequence_alignment_methods 
WHERE method_name = 'MUSCLE';

SELECT species_id, gene_id
FROM sequence_alignments
WHERE alignment = 'Compare Regions (GL192837.1:48,321-128,750:1)';

SELECT gene_name, description, COUNT(gene_name) OVER () AS total_protein_coding_genes
FROM genes
WHERE gene_type = 'protein_coding';

SELECT orthologue_type, AVG(orthologue_confidence) AS average_confidence
   FROM orthologues
   GROUP BY orthologue_type;
